package com.agrios.platform.serviceappointment.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="provider_review",schema="service") public class ProviderReviewEntity { @Id private UUID id; @Column(nullable=false) private UUID tenantId; @Column(nullable=false,unique=true) private UUID appointmentId; @Column(nullable=false) private UUID providerId; @Column(nullable=false) private UUID farmerId; @Column(nullable=false) private int rating; @Column(columnDefinition="text") private String reviewText; @Column(nullable=false) private String status; @Column(nullable=false) private Instant createdAt; protected ProviderReviewEntity(){} public static ProviderReviewEntity create(UUID tenantId,UUID appointmentId,UUID providerId,UUID farmerId,int rating,String text){var v=new ProviderReviewEntity();v.id=UUID.randomUUID();v.tenantId=tenantId;v.appointmentId=appointmentId;v.providerId=providerId;v.farmerId=farmerId;v.rating=rating;v.reviewText=text;v.status="PUBLISHED";v.createdAt=Instant.now();return v;} public int rating(){return rating;}}
